```typescript
function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj = new Array(n).fill(0).map(() => []);
    const inDegree = new Array(n).fill(0);

    for (const [u, v, cost] of edges) {
        adj[u].push({ v, cost });
        inDegree[v]++;
    }

    const queue = [];
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            queue.push(i);
        }
    }

    const topologicalOrder = [];
    while (queue.length > 0) {
        const u = queue.shift()!;
        topologicalOrder.push(u);
        for (const { v, cost } of adj[u]) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let maxEdge = 0;
    for (const [u, v, cost] of edges) {
        maxEdge = Math.max(maxEdge, cost);
    }

    let low = 0;
    let high = maxEdge;
    let answer = -1;

    function check(mid: number): boolean {
        const dp = new Array(n).fill(Infinity);
        dp[0] = 0;
        for (const u of topologicalOrder) {
            if (!online[u]) continue;
            for (const { v, cost } of adj[u]) {
                if (cost >= mid && online[v]) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }
        return dp[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
