      if (inDegree[i] === 0) {

         queue.push(i);

      }

   }

   const topologicalOrder = [];

   while (queue.length > 0) {

      const u = queue.shift();

      topologicalOrder.push(u);

      for (const {v, cost} of adj[u]) {

         inDegree[v]--;

         if (inDegree[v] === 0) {

            queue.push(v);

         }

      }

   }

   // Now, topologicalOrder is the topological order of the original graph.

   // Now, find maxEdgeCost

   let maxEdgeCost = 0;

   for (const [u, v, cost] of edges) {

      if (cost > maxEdgeCost) {

         maxEdgeCost = cost;

      }

   }

   // Binary search between low and high

   let low = 0, high = maxEdgeCost;

   let answer = -1;

